const body = $input.first().json.body || $input.first().json;

if (!body?.data?.message) return [];

const data = body.data;
if (data.key?.fromMe === true) return [];

const remoteJid = data.key?.remoteJid || '';
if (remoteJid.includes('@g.us') || remoteJid.match(/\d+-\d+@/)) return [];

const mensaje = data.message?.conversation ||
                data.message?.extendedTextMessage?.text ||
                data.message?.imageMessage?.caption || '';
if (!mensaje.trim()) return [];

const numero = remoteJid.replace('@s.whatsapp.net','').replace('@lid','');
const nombre  = data.pushName || 'Cliente';
const instancia = body.instance || data.owner || '';
const ciudad = 'medellin';

const ctxInfo = data.message?.extendedTextMessage?.contextInfo;
const isFromAd = !!(ctxInfo?.externalAdReply || data.message?.advertisementReplyMessage || data.referral);

return [{ json: { numero, mensaje: mensaje.trim(), nombre, instancia, ciudad, isFromAd } }];

const { numero, mensaje, nombre, instancia, ciudad, isFromAd } = $input.first().json;

// ⚠️ MODO PRUEBA — botActivo siempre true. Restaurar horario real antes de producción.
const botActivo = true;

/* HORARIO PRODUCCIÓN MEDELLÍN — descomentar cuando salga a producción:
const now = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Bogota' }));
const day = now.getDay(); // 0=Dom, 1=Lun, ..., 6=Sab
const t = now.getHours() * 60 + now.getMinutes();
const T = (h) => h * 60;
let botActivo = false;
if (day >= 1 && day <= 5) botActivo = t >= T(18) || t < 450;  // Lun-Vie: 18:00-07:30 (abre 7:30am)
else if (day === 6)        botActivo = t >= T(17) || t < T(8); // Sab: 17:00-08:00 (abre 8am)
else if (day === 0)        botActivo = t >= T(13) || t < T(9); // Dom/Fest: 13:00-09:00 (abre 9am)
*/

return [{ json: { numero, mensaje, nombre, instancia, ciudad, isFromAd, botActivo } }];

const searchTerm = query;
let token;
try {
