    headers: { 'partner_id': 'ferreteriayasiigo' },
    json: { username: 'ferreteriayacom@gmail.com', access_key: 'MGJkNGY1N2MtNDgyNC00NjI1LWIyY2MtZmMwMDMzNTcwNWE5Oj1xKDg4Nj1mclQ=' }
  });
  token = auth.access_token;
} catch(e) {
  return 'Catalogo no disponible. Usa BuscarEnWeb.';
}
try {
  const resp = await $helpers.httpRequest({
    method: 'GET',
    url: 'https://api.siigo.com/v1/products',
    headers: { 'Authorization': 'Bearer ' + token },
    searchParams: { page_size: 15, type: 'Product', search: searchTerm }
  });
  const results = (resp.results || []).filter(function(p) { return p.active; }).slice(0, 8);
  if (!results.length) return 'Producto no encontrado en catalogo para: ' + searchTerm;
  return 'Productos en catalogo (usa BuscarEnWeb para precio y link):\n' +
    results.map(function(p) { return '- ' + p.name; }).join('\n');
} catch(e) {
  return 'Error al verificar catalogo.';
}
